#!/usr/bin/env bash
set -Eeuo pipefail
export AWS_PAGER=""

PROJECT_DIR="$HOME/opsai-assistant-aws"
WEB_DIR="$PROJECT_DIR/app/web"
ASSET_DIR="$WEB_DIR/assets"
ENV_FILE="$PROJECT_DIR/.env"

cd "$PROJECT_DIR"

if [[ ! -f "$ENV_FILE" ]]; then
  echo "ERROR: $ENV_FILE was not found."
  exit 1
fi

if [[ ! -f "$WEB_DIR/index.html" ]]; then
  echo "ERROR: $WEB_DIR/index.html was not found."
  exit 1
fi

set -a
source "$ENV_FILE"
set +a

AWS_REGION="${AWS_REGION:-us-east-1}"
AMPLIFY_BRANCH_NAME="${AMPLIFY_BRANCH_NAME:-main}"

if [[ -z "${AMPLIFY_APP_ID:-}" ]]; then
  AMPLIFY_APP_ID="$(aws amplify list-apps \
    --region "$AWS_REGION" \
    --query "apps[?name=='opsai-assistant-ui'].appId | [0]" \
    --output text)"
fi

if [[ -z "$AMPLIFY_APP_ID" || "$AMPLIFY_APP_ID" == "None" ]]; then
  echo "ERROR: Amplify application was not found."
  exit 1
fi

DEFAULT_DOMAIN="$(aws amplify get-app \
  --app-id "$AMPLIFY_APP_ID" \
  --region "$AWS_REGION" \
  --query 'app.defaultDomain' \
  --output text)"

AMPLIFY_URL="https://${AMPLIFY_BRANCH_NAME}.${DEFAULT_DOMAIN}"

BACKUP_DIR="$PROJECT_DIR/backups/sidebar-chatbot-$(date +%Y%m%d-%H%M%S)"
mkdir -p "$BACKUP_DIR" "$ASSET_DIR"

cp "$WEB_DIR/index.html" "$BACKUP_DIR/index.html"

for file in \
  opsai-sidebar-chatbot.css \
  opsai-sidebar-chatbot.js
do
  if [[ -f "$WEB_DIR/$file" ]]; then
    cp "$WEB_DIR/$file" "$BACKUP_DIR/$file"
  fi
done

if [[ -f "$ASSET_DIR/opsai-sidebar-chatbot.jpg" ]]; then
  cp \
    "$ASSET_DIR/opsai-sidebar-chatbot.jpg" \
    "$BACKUP_DIR/opsai-sidebar-chatbot.jpg"
fi

echo "Backup created: $BACKUP_DIR"

cat > "$ASSET_DIR/opsai-sidebar-chatbot.jpg.b64" <<'OPSAI_IMAGE_EOF'

OPSAI_IMAGE_EOF

base64 --decode \
  "$ASSET_DIR/opsai-sidebar-chatbot.jpg.b64" \
  > "$ASSET_DIR/opsai-sidebar-chatbot.jpg"

rm -f "$ASSET_DIR/opsai-sidebar-chatbot.jpg.b64"

cat > "$WEB_DIR/opsai-sidebar-chatbot.css" <<'CSSEOF'
/* OpsAI animated sidebar chatbot */

.opsai-sidebar-chatbot {
  display: flex;
  align-items: center;
  justify-content: center;
  width: calc(100% - 24px);
  margin: 7px 12px 11px;
  pointer-events: none;
}

.opsai-sidebar-chatbot-frame {
  position: relative;
  display: grid;
  width: 82px;
  height: 82px;
  place-items: center;
  border: 1px solid rgba(147, 197, 253, .42);
  border-radius: 24px;
  background:
    radial-gradient(
      circle at 50% 35%,
      rgba(96, 165, 250, .20),
      rgba(30, 64, 175, .07) 70%
    );
  box-shadow:
    inset 0 0 0 1px rgba(255, 255, 255, .04),
    0 8px 24px rgba(2, 6, 23, .22);
}

.opsai-sidebar-chatbot-image {
  display: block;
  width: 74px;
  height: 74px;
  border: 2px solid rgba(219, 234, 254, .85);
  border-radius: 21px;
  object-fit: cover;
  object-position: center;
  box-shadow:
    0 8px 20px rgba(37, 99, 235, .22),
    0 0 18px rgba(56, 189, 248, .12);
  animation:
    opsai-sidebar-bot-float 3.6s ease-in-out infinite,
    opsai-sidebar-bot-glow 4.8s ease-in-out infinite;
  transform-origin: center;
}

.opsai-sidebar-chatbot-status {
  position: absolute;
  right: 3px;
  bottom: 4px;
  width: 12px;
  height: 12px;
  border: 2px solid #17345f;
  border-radius: 50%;
  background: #22c55e;
  box-shadow: 0 0 10px rgba(34, 197, 94, .75);
}

@keyframes opsai-sidebar-bot-float {
  0%,
  100% {
    transform: translateY(0) rotate(-0.6deg);
  }

  50% {
    transform: translateY(-5px) rotate(0.6deg);
  }
}

@keyframes opsai-sidebar-bot-glow {
  0%,
  100% {
    filter: brightness(1) saturate(1);
  }

  50% {
    filter: brightness(1.05) saturate(1.08);
  }
}

@media (max-height: 760px) {
  .opsai-sidebar-chatbot {
    margin-top: 4px;
    margin-bottom: 7px;
  }

  .opsai-sidebar-chatbot-frame {
    width: 70px;
    height: 70px;
    border-radius: 20px;
  }

  .opsai-sidebar-chatbot-image {
    width: 63px;
    height: 63px;
    border-radius: 17px;
  }
}

@media (prefers-reduced-motion: reduce) {
  .opsai-sidebar-chatbot-image {
    animation: none;
  }
}
CSSEOF

cat > "$WEB_DIR/opsai-sidebar-chatbot.js" <<'JSEOF'
(() => {
  let attempts = 0;

  function installSidebarChatbot() {
    attempts += 1;

    if (document.getElementById('opsai-sidebar-chatbot')) {
      return;
    }

    const sidebar =
      document.getElementById('sidebar') ||
      document.querySelector('.sidebar');

    const newChatButton =
      document.getElementById('new-chat-button');

    if (!sidebar) {
      if (attempts < 80) {
        window.setTimeout(installSidebarChatbot, 120);
      }

      return;
    }

    const container = document.createElement('div');
    container.id = 'opsai-sidebar-chatbot';
    container.className = 'opsai-sidebar-chatbot';
    container.setAttribute(
      'aria-label',
      'OpsAI chatbot assistant illustration'
    );

    container.innerHTML = `
      <div class="opsai-sidebar-chatbot-frame">
        <img
          class="opsai-sidebar-chatbot-image"
          src="assets/opsai-sidebar-chatbot.jpg"
          alt="Friendly OpsAI chatbot assistant"
        >
        <span
          class="opsai-sidebar-chatbot-status"
          aria-hidden="true"
        ></span>
      </div>
    `;

    if (newChatButton) {
      newChatButton.insertAdjacentElement(
        'beforebegin',
        container
      );
    } else {
      const firstNavigation =
        sidebar.querySelector('.demo-nav');

      if (firstNavigation) {
        firstNavigation.insertAdjacentElement(
          'beforebegin',
          container
        );
      } else {
        sidebar.appendChild(container);
      }
    }
  }

  if (document.readyState === 'loading') {
    document.addEventListener(
      'DOMContentLoaded',
      installSidebarChatbot,
      { once: true }
    );
  } else {
    installSidebarChatbot();
  }
})();
JSEOF

python3 - <<'PY'
from pathlib import Path
import re
import time

index_file = (
    Path.home()
    / "opsai-assistant-aws"
    / "app"
    / "web"
    / "index.html"
)

content = index_file.read_text(encoding="utf-8")
version = str(int(time.time()))

content = re.sub(
    r'\s*<link[^>]+href=["\'][^"\']*opsai-sidebar-chatbot\.css[^"\']*["\'][^>]*>\s*',
    '\n',
    content,
    flags=re.IGNORECASE
)

content = re.sub(
    r'\s*<script[^>]+src=["\'][^"\']*opsai-sidebar-chatbot\.js[^"\']*["\'][^>]*>\s*</script>\s*',
    '\n',
    content,
    flags=re.IGNORECASE
)

css_tag = (
    f'  <link rel="stylesheet" '
    f'href="opsai-sidebar-chatbot.css?v={version}">'
)

js_tag = (
    f'  <script '
    f'src="opsai-sidebar-chatbot.js?v={version}"></script>'
)

if "</head>" not in content or "</body>" not in content:
    raise SystemExit(
        "ERROR: index.html is missing </head> or </body>."
    )

content = content.replace(
    "</head>",
    f"{css_tag}\n</head>",
    1
)

content = content.replace(
    "</body>",
    f"{js_tag}\n</body>",
    1
)

index_file.write_text(content, encoding="utf-8")

print(
    "Sidebar chatbot references added "
    f"with version {version}."
)
PY

node --check "$WEB_DIR/opsai-sidebar-chatbot.js"

test -s "$ASSET_DIR/opsai-sidebar-chatbot.jpg"

grep -q "opsai-sidebar-chatbot.css" \
  "$WEB_DIR/index.html"

grep -q "opsai-sidebar-chatbot.js" \
  "$WEB_DIR/index.html"

grep -q "opsai-sidebar-bot-float" \
  "$WEB_DIR/opsai-sidebar-chatbot.css"

echo "Sidebar chatbot validation passed."

rm -f "$PROJECT_DIR/app/opsai-assistant-ui.zip"

(
  cd "$WEB_DIR"
  zip -qr ../opsai-assistant-ui.zip .
)

DEPLOYMENT_OUTPUT="$(aws amplify create-deployment \
  --app-id "$AMPLIFY_APP_ID" \
  --branch-name "$AMPLIFY_BRANCH_NAME" \
  --region "$AWS_REGION" \
  --output json)"

JOB_ID="$(echo "$DEPLOYMENT_OUTPUT" | python3 -c \
  'import json,sys; print(json.load(sys.stdin)["jobId"])')"

UPLOAD_URL="$(echo "$DEPLOYMENT_OUTPUT" | python3 -c \
  'import json,sys; print(json.load(sys.stdin)["zipUploadUrl"])')"

echo "Amplify deployment job: $JOB_ID"

curl -sS \
  --upload-file "$PROJECT_DIR/app/opsai-assistant-ui.zip" \
  "$UPLOAD_URL"

aws amplify start-deployment \
  --app-id "$AMPLIFY_APP_ID" \
  --branch-name "$AMPLIFY_BRANCH_NAME" \
  --job-id "$JOB_ID" \
  --region "$AWS_REGION" \
  >/dev/null

while true
do
  STATUS="$(aws amplify get-job \
    --app-id "$AMPLIFY_APP_ID" \
    --branch-name "$AMPLIFY_BRANCH_NAME" \
    --job-id "$JOB_ID" \
    --region "$AWS_REGION" \
    --query 'job.summary.status' \
    --output text)"

  echo "Deployment status: $STATUS"

  case "$STATUS" in
    SUCCEED)
      break
      ;;

    FAILED|CANCELLED)
      echo "ERROR: Amplify deployment failed."
      exit 1
      ;;

    *)
      sleep 10
      ;;
  esac
done

echo
echo "============================================================"
echo "OpsAI animated sidebar chatbot deployed successfully."
echo "============================================================"
echo
echo "URL: $AMPLIFY_URL"
echo
echo "Open in Incognito or press Ctrl + Shift + R."
